load("@rules_rust//rust:defs.bzl", "rust_binary") rust_binary(name, deps, srcs, data, aliases, allocator_libraries, alwayslink, binary_name, compile_data, crate_features, crate_name, crate_root, crate_type, edition, env, experimental_use_cc_common_link, link_deps, linker_script, lint_config, malloc, platform, proc_macro_deps, require_explicit_unstable_features, rustc_env, rustc_env_files, rustc_flags, stamp, unstable_rust_features_config, version, zself_profile_events) Builds a Rust binary crate. Example: Suppose you have the following directory structure for a Rust project with a library crate, hello_lib, and a binary crate, hello_world that uses the hello_lib library: [workspace]/ WORKSPACE hello_lib/ BUILD src/ lib.rs hello_world/ BUILD src/ main.rs hello_lib/src/lib.rs: pub struct Greeter { greeting: String,
} impl Greeter { pub fn new(greeting: &str) -> Greeter { Greeter { greeting: greeting.to_string(), } } pub fn greet(&self, thing: &str) { println!("{} {}", &self.greeting, thing); }
} hello_lib/BUILD: package(default_visibility = ["//visibility:public"]) load("@rules_rust//rust:defs.bzl", "rust_library") rust_library( name = "hello_lib", srcs = ["src/lib.rs"],
) hello_world/src/main.rs: extern crate hello_lib; fn main() { let hello = hello_lib::Greeter::new("Hello"); hello.greet("world");
} hello_world/BUILD: load("@rules_rust//rust:defs.bzl", "rust_binary") rust_binary( name = "hello_world", srcs = ["src/main.rs"], deps = ["//hello_lib"],
) Build and run hello_world: $ bazel run //hello_world
